const NAV_LINKS = ["About","Skills","Experience","Projects","Education","Contact"];

function useScrollSpy() {
  const [active, setActive] = useState("");
  useEffect(() => {
    const h = () => {
      for (const id of [...NAV_LINKS].reverse()) {
        const el = document.getElementById(id.toLowerCase());
        if (el && window.scrollY >= el.offsetTop - 130) { setActive(id); break; }
      }
    };
    window.addEventListener("scroll", h, { passive:true });
    return () => window.removeEventListener("scroll", h);
  }, []);
  return active;
}

function useInView(threshold = 0.08) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) { setVisible(true); obs.disconnect(); } },
      { threshold }
    );
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, [threshold]);
  return [ref, visible];
}

function scrollTo(id) {
  const el = document.getElementById(id.toLowerCase());
  if (el) el.scrollIntoView({ behavior:"smooth", block:"start" });
}

function FadeUp({ children, delay=0, from="bottom", style }) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) { setVisible(true); obs.disconnect(); } },
      { threshold: 0, rootMargin: "0px 0px -50px 0px" }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, []);
  const hidden = {
    bottom: "translateY(40px)",
    left:   "translateX(-40px)",
    right:  "translateX(40px)",
    scale:  "scale(0.94)",
  }[from] || "translateY(40px)";
  return (
    <div ref={ref} style={{
      transition: `opacity 0.75s cubic-bezier(0.22,1,0.36,1) ${delay}ms, transform 0.75s cubic-bezier(0.22,1,0.36,1) ${delay}ms`,
      opacity: visible ? 1 : 0,
      transform: visible ? "none" : hidden,
      ...(style||{}),
    }}>
      {children}
    </div>
  );
}

function Counter({ value, suffix, animate }) {
  const str = value % 1 !== 0 ? value.toFixed(1) : String(Math.round(value));
  return (
    <span style={{ display:"inline-flex", alignItems:"flex-end" }}>
      {str.split("").map((ch, i) => (
        <span key={i} style={{
          display:"inline-block",
          opacity: animate ? 1 : 0,
          transform: animate ? "translateY(0)" : "translateY(24px)",
          transition: animate
            ? `opacity 0.5s ease ${i * 0.1}s, transform 0.6s cubic-bezier(0.34,1.56,0.64,1) ${i * 0.1}s`
            : "none",
        }}>{ch}</span>
      ))}
      {suffix && (
        <span style={{
          display:"inline-block",
          opacity: animate ? 1 : 0,
          transform: animate ? "translateY(0)" : "translateY(24px)",
          transition: animate
            ? `opacity 0.5s ease ${str.length * 0.1}s, transform 0.6s cubic-bezier(0.34,1.56,0.64,1) ${str.length * 0.1}s`
            : "none",
        }}>{suffix}</span>
      )}
    </span>
  );
}





function CurrentlyDoing() {
  const items = data.currentlyBuilding;
  const [idx, setIdx] = useState(0);
  const [visible, setVisible] = useState(true);
  useEffect(() => {
    const t = setInterval(() => {
      setVisible(false);
      setTimeout(() => {
        setIdx(i => (i+1) % items.length);
        setVisible(true);
      }, 400);
    }, 3500);
    return () => clearInterval(t);
  }, []);
  return (
    <div style={st.currentlyWrap}>
      <span style={st.currentlyDot}/>
      <span style={st.currentlyLabel}>Currently —</span>
      <span style={{
        ...st.currentlyText,
        opacity: visible ? 1 : 0,
        transform: visible ? "translateY(0)" : "translateY(8px)",
        transition: "opacity 0.5s ease, transform 0.5s ease",
        display:"inline-block",
      }}>
        {items[idx]}
      </span>
    </div>
  );
}



function TypeOnce({ text }) {
  const [displayed, setDisplayed] = useState("");
  const [done, setDone] = useState(false);
  const ref = useRef(null);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting && !done) {
        obs.disconnect();
        let i = 0;
        const interval = setInterval(() => {
          setDisplayed(text.slice(0, i+1));
          i++;
          if (i >= text.length) { clearInterval(interval); setDone(true); }
        }, 38);
      }
    }, { threshold: 0.5 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return (
    <span ref={ref}>
      {displayed}
      {!done && <span style={{ borderRight:"2px solid #48B5C8", marginLeft:"1px", animation:"blink 0.7s step-end infinite" }}/>}
    </span>
  );
}



