  bar:{ display:"block", width:"22px", height:"2px", background:C.white, transition:"all 0.3s" },
  barOpen1:{ transform:"translateY(7px) rotate(45deg)" },
  barOpen2:{ opacity:0 },
  barOpen3:{ transform:"translateY(-7px) rotate(-45deg)" },
  mobileMenu:{ position:"fixed", top:"60px", left:0, right:0, zIndex:99, background:"rgba(14,12,10,0.97)", backdropFilter:"blur(14px)", display:"flex", flexDirection:"column", padding:"1.5rem 2rem", borderBottom:`1px solid ${C.beige}` },
  mobileLink:{ background:"none", border:"none", cursor:"pointer", fontFamily:"'Times New Roman',Times,serif", fontSize:"1.05rem", letterSpacing:"0.1em", color:C.text, padding:"0.7rem 0", textAlign:"left", textTransform:"uppercase", borderBottom:`1px solid rgba(255,255,255,0.08)`, fontWeight:500 },
  mobileLinkResume:{ fontFamily:"'Times New Roman',Times,serif", fontSize:"1.05rem", letterSpacing:"0.1em", color:C.teal, padding:"0.8rem 0", textAlign:"left", textTransform:"uppercase", textDecoration:"none", fontWeight:700 },

  // ── HERO ──────────────────────────────────────────────────────────────────
  hero:{ position:"relative", background:C.bg },

  // Photo banner — upper portion, fixed height
