  // Content block — appears to sit below the photo, overlapping the fade
  heroDecorRing1:{ position:"absolute", top:"-80px", left:"-80px", width:"340px", height:"340px", borderRadius:"50%", border:"1px solid rgba(28,78,106,0.07)", pointerEvents:"none", zIndex:0 },
  heroDecorRing2:{ position:"absolute", bottom:"-60px", right:"-60px", width:"280px", height:"280px", borderRadius:"50%", border:"1px solid rgba(107,45,62,0.07)", pointerEvents:"none", zIndex:0 },
  heroContent:{ position:"relative", zIndex:1, maxWidth:"900px", margin:"-4rem auto 0", padding:"0 3rem 3rem", textAlign:"center", display:"flex", flexDirection:"column", alignItems:"center" },
  heroBadge:{ display:"none" },
  heroBadgePlain:{ fontFamily:"'Times New Roman',Times,serif", fontSize:"0.78rem", letterSpacing:"0.2em", textTransform:"uppercase", color:C.teal, marginBottom:"1.75rem", fontWeight:600, display:"inline-block", border:"1px solid rgba(28,78,106,0.18)", borderRadius:"30px", padding:"0.5rem 1.4rem", background:"rgba(255,255,255,0.45)", backdropFilter:"blur(8px)" },
