  heroName:{ fontFamily:"'Times New Roman',Times,serif", fontSize:"clamp(2.8rem,5.5vw,5rem)", fontWeight:400, letterSpacing:"-0.02em", lineHeight:1.04, color:"#F0ECE6", margin:"0 0 0.6rem", textAlign:"center", width:"100%" },
  heroLocation:{ fontFamily:"'Times New Roman',Times,serif", fontSize:"0.78rem", letterSpacing:"0.2em", textTransform:"uppercase", color:"rgba(255,255,255,0.45)", marginBottom:"0.9rem", fontWeight:500 },
  heroSubChips:{ display:"flex", alignItems:"center", justifyContent:"center", flexWrap:"wrap", gap:"0", marginBottom:"1rem" },
  heroSubChip:{ fontFamily:"'Times New Roman',Times,serif", fontSize:"0.85rem", letterSpacing:"0.12em", textTransform:"uppercase", color:"rgba(255,255,255,0.7)", fontWeight:500, display:"flex", alignItems:"center" },
  heroSubChipDot:{ margin:"0 0.6rem", color:C.sand, fontWeight:400, fontSize:"1rem" },
  heroTitle:{ fontFamily:"'Times New Roman',Times,serif", fontSize:"1.05rem", fontWeight:600, letterSpacing:"0.1em", textTransform:"uppercase", color:C.teal, marginBottom:"1rem" },
