  projBadge:{ fontFamily:"'Times New Roman',Times,serif", fontSize:"0.58rem", letterSpacing:"0.12em", textTransform:"uppercase", color:"rgba(255,255,255,0.7)", background:"rgba(255,255,255,0.08)", border:"1px solid rgba(255,255,255,0.15)", padding:"0.2rem 0.6rem", borderRadius:"3px", fontWeight:600, whiteSpace:"nowrap", flexShrink:0 },
  caseStudyToggle:{ fontFamily:"'Times New Roman',Times,serif", fontSize:"0.7rem", letterSpacing:"0.12em", textTransform:"uppercase", color:C.teal, fontWeight:700, cursor:"pointer", marginLeft:"auto" },
  projTitle:{ fontFamily:"'Times New Roman',Times,serif", fontSize:"1.15rem", fontWeight:700, color:"#F0ECE6", lineHeight:1.3, margin:0 },
  projSummary:{ fontFamily:"'Times New Roman',Times,serif", fontSize:"0.85rem", lineHeight:1.65, color:"rgba(255,255,255,0.5)", margin:0, fontWeight:400 },
  projImpact:{ fontFamily:"'Times New Roman',Times,serif", fontSize:"0.84rem", color:C.burgundy, margin:0, fontWeight:700, letterSpacing:"0.01em" },
  projStack:{ display:"flex", flexWrap:"wrap", gap:"0.4rem" },
  projGithubLink:{ color:C.taupe, transition:"color 0.2s", flexShrink:0, marginLeft:"0.5rem", display:"flex", alignItems:"center" },
  projTag:{ fontFamily:"'Times New Roman',Times,serif", fontSize:"0.68rem", letterSpacing:"0.08em", color:"rgba(255,255,255,0.45)", background:"rgba(255,255,255,0.06)", padding:"0.2rem 0.55rem", borderRadius:"3px", fontWeight:500 },
  caseStudyBody:{ borderRadius:"4px" },
  csDivider:{ height:"1px", background:C.beige, margin:"0.25rem 0 1.2rem" },
  csRow:{ display:"grid", gridTemplateColumns:"72px 1fr", gap:"0.5rem 1rem", marginBottom:"0.9rem" },
  csLabel:{ fontFamily:"'Times New Roman',Times,serif", fontSize:"0.67rem", letterSpacing:"0.18em", textTransform:"uppercase", color:C.teal, fontWeight:700, paddingTop:"0.18rem" },
  csText:{ fontFamily:"'Times New Roman',Times,serif", fontSize:"0.95rem", lineHeight:1.72, color:C.textMuted, fontWeight:500, margin:0 },

  skillsGrid:{ display:"flex", flexDirection:"column", gap:"1.1rem" },
