  skillCategory:{ fontFamily:"'Times New Roman',Times,serif", fontSize:"0.88rem", letterSpacing:"0.12em", textTransform:"uppercase", color:"#48B5C8", fontWeight:700, whiteSpace:"nowrap", flexShrink:0, width:"160px" },
  skillPillGroup:{ display:"flex", flexWrap:"wrap", alignItems:"center", gap:"0 0" },
